(window.webpackJsonp=window.webpackJsonp||[]).push([[355],{982:function(n,e){n.exports='\x3c!-- \ntitle: Three.js\nsort: \n--\x3e \n\n> 使用\n\n### HelloWorld\n\n> 创建一个立方体\n>\n> [预览](https://threejsfundamentals.org/threejs/threejs-fundamentals-with-light.html)\n\n```html\n<!DOCTYPE html>\n<html lang="en">\n\n<head>\n  <meta charset="UTF-8">\n  <meta http-equiv="X-UA-Compatible" content="IE=edge">\n  <meta name="viewport" content="width=device-width, initial-scale=1.0">\n  <title>Document</title>\n</head>\n\n<body>\n  <canvas id="demo"></canvas>\n  <script src="https://cdn.bootcdn.net/ajax/libs/three.js/r128/three.js"><\/script>\n  <script>\n    function main() {\n      const canvas = document.querySelector(\'#demo\');\n      const renderer = new THREE.WebGLRenderer({ canvas });\n      // 摄像机参数\n      const fov = 75;     // 视野范围75°\n      const aspect = 2;   // 画布宽高比\n      const near = 0.1;   // 可视最近距离\n      const far = 5;      // 可视最远距离\n      const camera = new THREE.PerspectiveCamera(fov, aspect, near, far);\n      // 相机默认在坐标原点，先Z轴正方向移动2，即可看到原点图像\n      camera.position.z = 2;\n      // 新建场景\n      const scene = new THREE.Scene();\n      // 光照效果\n      {\n        const color = 0xFFFFFF;\n        const intensity = 1;\n        const light = new THREE.DirectionalLight(color, intensity);\n        light.position.set(-1, 2, 4);\n        scene.add(light);\n      }\n      // 创建盒子\n      const boxWidth = 1;\n      const boxHeight = 1;\n      const boxDepth = 1;\n      const geometry = new THREE.BoxGeometry(boxWidth, boxHeight, boxDepth);\n\n      // 创建材质\n      const material = new THREE.MeshPhongMaterial({ color: 0x44aa88 });  // greenish blue\n\n      // 创建一个网格对象\n      const cube = new THREE.Mesh(geometry, material);\n      scene.add(cube);\n\n      // 动起来\n      function render(time) {\n        time *= 0.001;  // 毫秒转换为秒\n\n        cube.rotation.x = time;\n        cube.rotation.y = time;\n        // 重新渲染新一帧\n        renderer.render(scene, camera);\n\n        requestAnimationFrame(render);\n      }\n      requestAnimationFrame(render);\n\n    }\n\n    main();\n  <\/script>\n</body>\n\n</html>\n```\n\n### Fun\n\n```js\n// 贴图\nconst material = new THREE.MeshPhongMaterial({ \n  map: new THREE.TextureLoader().load("logo.jpg")\n});\n```\n\n'}}]);